function debounce(fn, delay, options = {}) {
  const { leading = false, trailing = true } = options;
  let timer = null;
  let lastArgs = null;
  let lastThis = null;

  function invoke() {
    if (!timer) return;
    clearTimeout(timer);
    timer = null;
    if (trailing && lastArgs) {
      fn.apply(lastThis, lastArgs);
      lastArgs = null;
      lastThis = null;
    }
  }

  function debounced(...args) {
    const callNow = leading && !timer;

    lastArgs = args;
    lastThis = this;

    if (timer) clearTimeout(timer);

    if (callNow) {
      fn.apply(this, args);
      lastArgs = null;
      lastThis = null;
    }

    timer = setTimeout(invoke, delay);
  }

  debounced.cancel = function () {
    if (timer) clearTimeout(timer);
    timer = null;
    lastArgs = null;
    lastThis = null;
  };

  debounced.flush = function () {
    if (timer && trailing && lastArgs) {
      fn.apply(lastThis, lastArgs);
    }
    debounced.cancel();
  };

  return debounced;
}
```

**使用方式**

```javascript
// 基本用法：输入变化 300ms 后才触发
const save = debounce((text) => fetch('/api/save', { method: 'POST', body: text }), 300);
input.addEventListener('input', (e) => save(e.target.value));

// leading + trailing 都触发（比如按钮防连点：第一次立即执行，之后忽略快速重复点击）
const clickHandler = debounce(() => submit(), 500, { leading: true, trailing: false });
button.addEventListener('click', clickHandler);

// 手动取消或立即执行
debounced.cancel();
debounced.flush();
```

**几个要点**

- **leading vs trailing**：leading 在第一次调用时立即执行，之后延迟期内忽略后续调用；trailing 在延迟结束后执行最后一次调用。默认 trailing 模式。
- **cancel / flush**：cancel 取消待执行的调用；flush 立即执行挂起的最后一次调用然后取消。
- **this 绑定**：通过保留 `lastThis`，确保回调执行时的 `this` 上下文正确。
- **边界处理**：leading 模式下调用后立即清理 `lastArgs`，避免 trailing 重复执行。

